import type { MODE } from '../../interface';

export function isSelectCell({
  selectedDates,
  selectedRange,
  date,
  mode,
}: {
  mode: MODE;
  date: moment.Moment;
  selectedDates: moment.Moment[];
  selectedRange?: [moment.Moment, moment.Moment];
}) {
  return [...selectedDates, ...(selectedRange || [])].some(d => d.isSame(date, mode));
}
